    full_path = os.path.join(dir_path, filename)
    absolute_full_path = os.path.abspath(full_path)
    absolute_dir_path = os.path.abspath(dir_path)

    if not absolute_full_path.startswith(absolute_dir_path):
        return ""

    try:
        with open(full_path, 'r') as f:
            return f.read()
    except Exception:
        return ""

