import re

def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if ' ' in password:
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[0-9]', password):
        return False
    if not re.search(r'[^A-Za-z0-9]', password):
        return False
    common_passwords = {'admin', 'password', '123456', 'qwerty', 'letmein', '123456789', '000000', '111111', '123123', 'abc123', 'abc', '1234567890'}
    if password in common_passwords:
        return False
    return True

